            </button>

            {isModalOpen && (
                <Modal title="إضافة استثمار جديد" onClose={() => setIsModalOpen(false)}>
                    <InvestmentForm onSuccess={() => { setIsModalOpen(false); handleDatabaseChange(); fetchInvestments(); }} onCancel={() => setIsModalOpen(false)} />
