import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { supabase } from '../lib/supabase';
import { Contact, Debt } from '../types';
import {
    PencilSquareIcon,
    TrashIcon,
    PlusIcon,
    XMarkIcon,
    ExclamationTriangleIcon,
    DocumentArrowDownIcon,
    ArrowRightIcon,
    WalletIcon,
    ScaleIcon,
    CalendarDaysIcon,
    CheckCircleIcon
} from './icons';

interface ContactProfilePageProps {
    contactId: string;
    onBack: () => void;
    handleDatabaseChange: (description?: string) => void;
}

const formatCurrency = (amount: number) => {
    const options: Intl.NumberFormatOptions = {
        style: 'currency',
        currency: 'LYD',
    };
    if (amount % 1 === 0) {
        options.minimumFractionDigits = 0;
        options.maximumFractionDigits = 0;
    } else {
        options.minimumFractionDigits = 2;
        options.maximumFractionDigits = 2;
    }
    return new Intl.NumberFormat('ar-LY', options).format(amount).replace('LYD', 'د.ل');
};

const getDebtStatus = (dueDate: string | null): 'ok' | 'due_soon' | 'overdue' => {
    if (!dueDate) return 'ok';
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const due = new Date(dueDate);

    const diffTime = due.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return 'overdue';
    if (diffDays <= 7) return 'due_soon';
    return 'ok';
};

const DebtForm: React.FC<{
    debt?: Debt;
    onSave: () => void;
    onCancel: () => void;
    contactId: string;
}> = ({ debt, onSave, onCancel, contactId }) => {
    const [type, setType] = useState<'for_you' | 'on_you'>(debt?.type || 'on_you');
    const [amount, setAmount] = useState(debt?.amount?.toString() || '');
    const [dueDate, setDueDate] = useState(debt?.due_date ? new Date(debt.due_date).toISOString().split('T')[0] : '');
    const [description, setDescription] = useState(debt?.description || '');
    const [isSaving, setIsSaving] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSaving(true);
        const debtData = {
            type,
            amount: Number(amount),
            contact_id: contactId,
            due_date: dueDate || null,
            description,
            paid: debt?.paid || false,
        };

        const { error } = debt?.id
            ? await supabase.from('debts').update(debtData).eq('id', debt.id)
            : await supabase.from('debts').insert(debtData);

        if (error) {
            console.error('Error saving debt:', error.message);
            alert('حدث خطأ أثناء حفظ الدين.');
        } else {
            onSave();
        }
        setIsSaving(false);
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-4">
            <div>
                <label className="block text-sm font-medium text-slate-300 mb-1">نوع الدين</label>
                <div className="flex gap-4">
                    <button type="button" onClick={() => setType('on_you')} className={`w-full p-2 rounded-xl font-bold transition ${type === 'on_you' ? 'bg-red-500 text-white shadow-lg shadow-red-900/20' : 'bg-slate-700 text-slate-400'}`}>دين عليك</button>
                    <button type="button" onClick={() => setType('for_you')} className={`w-full p-2 rounded-xl font-bold transition ${type === 'for_you' ? 'bg-green-500 text-white shadow-lg shadow-green-900/20' : 'bg-slate-700 text-slate-400'}`}>دين لك</button>
                </div>
            </div>
            <div>
                <label htmlFor="amount" className="block text-sm font-medium text-slate-300 mb-1">المبلغ</label>
                <input type="number" step="0.01" id="amount" value={amount} onChange={e => setAmount(e.target.value)} required className="w-full bg-slate-700 border border-slate-600 rounded-xl p-3 text-white focus:outline-none focus:border-cyan-500" />
            </div>
            <div>
                <label htmlFor="due_date" className="block text-sm font-medium text-slate-300 mb-1">تاريخ الاستحقاق (اختياري)</label>
                <input type="date" id="due_date" value={dueDate} onChange={e => setDueDate(e.target.value)} className="w-full bg-slate-700 border border-slate-600 rounded-xl p-3 text-white focus:outline-none focus:border-cyan-500" />
            </div>
            <div>
                <label htmlFor="description" className="block text-sm font-medium text-slate-300 mb-1">الوصف (اختياري)</label>
                <textarea id="description" value={description} onChange={e => setDescription(e.target.value)} rows={2} className="w-full bg-slate-700 border border-slate-600 rounded-xl p-3 text-white focus:outline-none focus:border-cyan-500 resize-none" placeholder="سبب الدين..."></textarea>
            </div>
            <div className="flex justify-end gap-3 pt-4">
                <button type="button" onClick={onCancel} className="py-2 px-4 text-slate-400 hover:text-white font-bold transition">إلغاء</button>
                <button type="submit" disabled={isSaving} className="py-3 px-8 bg-cyan-600 hover:bg-cyan-500 text-white rounded-xl transition font-bold shadow-lg shadow-cyan-900/20">
                    {isSaving ? 'جاري الحفظ...' : 'حفظ الدين'}
                </button>
            </div>
        </form>
    );
};

const Modal: React.FC<{ children: React.ReactNode; title: string; onClose: () => void; }> = ({ children, title, onClose }) => (
    <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-md flex items-center justify-center p-4 animate-fade-in">
        <div className="glass-card bg-slate-800 rounded-3xl p-6 w-full max-w-md border border-slate-700 shadow-xl animate-slide-up">
            <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-bold">{title}</h3>
                <button onClick={onClose} className="p-2 rounded-full bg-slate-700 text-slate-400 hover:text-white transition-colors"><XMarkIcon className="w-5 h-6" /></button>
            </div>
            {children}
        </div>
    </div>
);

const ContactProfilePage: React.FC<ContactProfilePageProps> = ({ contactId, onBack, handleDatabaseChange }) => {
    const [contact, setContact] = useState<Contact | null>(null);
    const [debts, setDebts] = useState<Debt[]>([]);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState<'on_you' | 'for_you'>('on_you');

    const [modal, setModal] = useState<{ type: 'add' | 'edit' | 'delete' | null, debt: Debt | null }>({ type: null, debt: null });

    const fetchData = useCallback(async () => {
        setLoading(true);
        const contactPromise = supabase.from('contacts').select('*').eq('id', contactId).single();
        const debtsPromise = supabase.from('debts').select('*').eq('contact_id', contactId).order('created_at', { ascending: false });

        const [{ data: contactData, error: contactError }, { data: debtsData, error: debtsError }] = await Promise.all([contactPromise, debtsPromise]);

        if (contactError) console.error("Error fetching contact:", contactError.message);
        else setContact(contactData);

        if (debtsError) console.error("Error fetching debts:", debtsError.message);
        else setDebts(debtsData as unknown as Debt[]);

        setLoading(false);
    }, [contactId]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const { forYou, onYou, netBalance } = useMemo(() => {
        const forYou = debts.filter(d => d.type === 'for_you' && !d.paid).reduce((sum, d) => sum + d.amount, 0);
        const onYou = debts.filter(d => d.type === 'on_you' && !d.paid).reduce((sum, d) => sum + d.amount, 0);
        return { forYou, onYou, netBalance: forYou - onYou };
    }, [debts]);

    const filteredDebts = debts.filter(d => d.type === activeTab && !d.paid);

    const handleSave = () => {
        const description = modal.debt ? `تعديل دين لـ ${contact?.name}` : `إضافة دين جديد لـ ${contact?.name}`;
        setModal({ type: null, debt: null });
        handleDatabaseChange(description);
        fetchData();
    };

    const handleDelete = async () => {
        if (!modal.debt) return;
        const description = `حذف دين لـ ${contact?.name}`;
        const { error } = await supabase.from('debts').delete().eq('id', modal.debt.id);
        if (error) {
            console.error('Error deleting debt', error.message);
            alert('حدث خطأ أثناء الحذف.');
        } else {
            setModal({ type: null, debt: null });
            handleDatabaseChange(description);
            fetchData();
        }
    };

    const handleTogglePaid = async (debt: Debt) => {
        const { error } = await supabase.from('debts').update({ paid: !debt.paid, paid_at: !debt.paid ? new Date().toISOString() : null }).eq('id', debt.id);
         if (error) {
            console.error('Error updating debt status', error.message);
            alert('حدث خطأ أثناء تحديث حالة الدين.');
        } else {
            const description = `تحديث حالة دين لـ ${contact?.name} إلى ${!debt.paid ? 'مدفوع' : 'غير مدفوع'}`;
            handleDatabaseChange(description);
            fetchData();
        }
    };

    const handleExportPDF = () => {
        // تأخير بسيط للتأكد من أن المتصفح قد قام بتصحيح عرض العناصر قبل الطباعة
        setTimeout(() => {
            window.print();
        }, 150);
    };

    if (loading) {
        return (
            <div className="flex flex-col items-center justify-center py-20 gap-4">
                <div className="w-12 h-12 border-4 border-cyan-500 border-t-transparent rounded-full animate-spin"></div>
                <p className="text-slate-500 font-bold">جاري تحميل الملف الشخصي...</p>
            </div>
        );
    }

    if (!contact) {
        return <div className="text-center p-8 bg-rose-500/10 rounded-2xl text-rose-400">لم يتم العثور على جهة الاتصال.</div>;
    }

    return (
        <div className="space-y-6 animate-fade-in relative">
            {/* Action Header */}
            <div className="flex justify-between items-center mb-2 px-1 print-hidden">
                <button onClick={onBack} className="p-2 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-xl transition flex items-center gap-2">
                    <ArrowRightIcon className="w-5 h-5" /> عودة
                </button>
                <button 
                    onClick={handleExportPDF} 
                    className="p-3 bg-white text-slate-900 rounded-xl font-bold flex items-center gap-2 hover:bg-cyan-50 transition-all shadow-xl shadow-white/5 active:scale-95"
                >
                    <DocumentArrowDownIcon className="w-5 h-5" /> تصدير PDF
                </button>
            </div>

            {/* Profile Header Card */}
            <div className="glass-card p-6 lg:p-8 rounded-[2.5rem] border border-white/5 bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 relative overflow-hidden print-hidden">
                <div className="absolute top-0 right-0 w-48 h-48 bg-cyan-500/10 rounded-full blur-[80px]"></div>
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 relative z-10">
                    <div className="flex items-center gap-5">
