                            {contact.name.split(' ').map(n => n[0]).join('')}
                        </div>
                        <div>
                            <h2 className="font-black text-3xl text-white mb-1">{contact.name}</h2>
                            <div className="flex flex-wrap gap-3">
                                {contact.phone && <span className="text-xs font-bold text-slate-400 flex items-center gap-1 bg-slate-800/80 px-2 py-1 rounded-lg border border-white/5">{contact.phone}</span>}
                                {contact.address && <span className="text-xs font-bold text-slate-400 flex items-center gap-1 bg-slate-800/80 px-2 py-1 rounded-lg border border-white/5">{contact.address}</span>}
