            {/* Financial Summary */}
            <div className="grid grid-cols-3 gap-4 print-hidden">
                 <div className="glass-card p-4 rounded-3xl border border-emerald-500/10 text-center">
                    <p className="text-[10px] text-emerald-400 font-bold uppercase tracking-widest mb-1">مستحق لك</p>
