                <div className={`glass-card p-4 rounded-3xl border text-center ${netBalance >= 0 ? 'border-cyan-500/10' : 'border-rose-500/20'}`}>
                    <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mb-1">الرصيد الصافي</p>
