                        ديون لك
                    </button>
                    <button onClick={() => setActiveTab('on_you')} className={`flex-1 py-3 rounded-xl font-bold transition-all duration-300 flex items-center justify-center gap-2 ${activeTab === 'on_you' ? 'bg-rose-500 text-white shadow-lg shadow-rose-900/30' : 'text-slate-500 hover:text-slate-300'}`}>
                        ديون عليك
                    </button>
                </div>

                {filteredDebts.length > 0 ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {filteredDebts.map(debt => {
                            const status = getDebtStatus(debt.due_date);
                            return (
                                <div key={debt.id} className="glass-card rounded-[1.5rem] p-5 border border-white/5 relative overflow-hidden group hover:border-white/10 transition-all">
