                                    <div className="flex justify-between items-start">
                                        <div className="flex-1 min-w-0">
                                            <p className="font-bold text-white text-lg truncate mb-1">{debt.description || 'دين بدون بيان'}</p>
                                            <div className="flex items-center gap-3 text-xs">
                                                <span className="text-slate-500 flex items-center gap-1 font-bold"><CalendarDaysIcon className="w-3.5 h-3.5"/> {new Date(debt.created_at).toLocaleDateString('ar-LY')}</span>
                                                {debt.due_date && (
                                                    <span className={`px-2 py-0.5 rounded-lg font-bold flex items-center gap-1 ${status === 'ok' ? 'bg-slate-800 text-slate-400' : status === 'due_soon' ? 'bg-amber-500/10 text-amber-400' : 'bg-rose-500/10 text-rose-400'}`}>
                                                        <ExclamationTriangleIcon className="w-3 h-3"/> {new Date(debt.due_date).toLocaleDateString('ar-LY')}
                                                    </span>
                                                )}
                                            </div>
                                        </div>
                                        <div className="text-left">
                                            <p className={`font-black text-xl ${debt.type === 'for_you' ? 'text-emerald-400' : 'text-rose-400'}`}>{formatCurrency(debt.amount)}</p>
                                            <button onClick={() => handleTogglePaid(debt)} className="text-[10px] font-bold text-slate-500 hover:text-emerald-400 transition-colors mt-2">تعليم كمدفوع</button>
