                                        <button onClick={() => setModal({ type: 'delete', debt })} className="p-2 bg-white/5 hover:bg-rose-500/10 text-slate-400 hover:text-rose-400 rounded-lg transition-colors"><TrashIcon className="w-4 h-4"/></button>
                                    </div>
